                { "base", "BTC" },
                { "quote", "USD" },
                { "baseId", "Btc" },
                { "quoteId", "Usd" },
                { "type", "spot" },
                { "spot", true },
            };
            var exchange2 = new ccxt.Exchange(new Dictionary<string, object>() {
                { "id", "sampleexchange" },
                { "markets", new Dictionary<string, object>() {
                    { "BTC/USD", sampleMarket },
                } },
            });
            Assert(!isEqual(getValue(exchange2.markets, "BTC/USD"), null));
        }
